import{_ as t,o as r,c as e,ag as p}from"./chunks/framework.ETe_P6d1.js";const l=JSON.parse('{"title":"开平近代建筑装饰符号的“分离”与“并置”****——两种文化协商策略的比较研究","description":"","frontmatter":{},"headers":[],"relativePath":"reports/邓舒文/邓舒文_关于开平近代建筑装饰符号的“分离”与“并置”的调研报告.md.md","filePath":"reports/邓舒文/邓舒文_关于开平近代建筑装饰符号的“分离”与“并置”的调研报告.md.md"}'),o={name:"reports/邓舒文/邓舒文_关于开平近代建筑装饰符号的“分离”与“并置”的调研报告.md.md"};function n(s,a,i,g,h,d){return r(),e("div",null,[...a[0]||(a[0]=[p('<h1 id="开平近代建筑装饰符号的-分离-与-并置-——两种文化协商策略的比较研究" tabindex="-1"><strong>开平近代建筑装饰符号的“分离”与“并置”****——两种文化协商策略的比较研究</strong> <a class="header-anchor" href="#开平近代建筑装饰符号的-分离-与-并置-——两种文化协商策略的比较研究" aria-label="Permalink to &quot;**开平近代建筑装饰符号的“分离”与“并置”****——两种文化协商策略的比较研究**&quot;">​</a></h1><p>考察地点： 广东省江门市开平市</p><p>考察时间： 2026年3月31日</p><p>考察学生： 邓舒文</p><p>指导教师： 石拓老师</p><h3 id="一、问题的提出-超越-中西融合-的简化叙事" tabindex="-1">一、<strong>问题的提出：超越“中西融合”的简化叙事</strong> <a class="header-anchor" href="#一、问题的提出-超越-中西融合-的简化叙事" aria-label="Permalink to &quot;一、**问题的提出：超越“中西融合”的简化叙事**&quot;">​</a></h3><p>开平近代建筑长期被标签化为“中西合璧”或“中西融合”的典型案例，但这种表述遮蔽了更为复杂的文化协商过程。2026年4月，在田野调查中本人刚抵达开平，在仓东村某碉楼拍摄到斑驳墙面与“仓东计划””展牌并置的场景（图1），成为本研究的问题起点：当保护计划介入历史空间，装饰符</p><p>号的命运将如何？当我们对比立园与赤坎古镇——同为华侨建造、同处开平地域、同一历史时期，却呈现出截然不同的装饰策略时，核心问题浮现：为什么立园选择了“中式主体、西式为用”的深层分离，而赤坎却呈现出“中西并置”的表层竞争？ 这两种策略背后蕴含着怎样的社会分层、身份政治与空间逻辑？</p><p>![图片 1：仓东村斑驳墙面与&quot;仓东计划&quot;展牌并置场景](images/图片 1.png)</p><h3 id="二、-案例对比-立园的-分离策略-与赤坎的-并置策略" tabindex="-1">**二、**<strong>案例对比：立园的“分离策略”与赤坎的“并置策略”</strong> <a class="header-anchor" href="#二、-案例对比-立园的-分离策略-与赤坎的-并置策略" aria-label="Permalink to &quot;**二、****案例对比：立园的“分离策略”与赤坎的“并置策略”**&quot;">​</a></h3><h3 id="_2-1-立园-精英园林的-深层和谐" tabindex="-1"><strong>2.1</strong> <strong>立园：精英园林的“深层和谐”</strong> <a class="header-anchor" href="#_2-1-立园-精英园林的-深层和谐" aria-label="Permalink to &quot;**2.1** **立园：精英园林的“深层和谐”**&quot;">​</a></h3><p>![图片 2：立园主楼泮立楼外观（垂直分层三段式结构）](images/图片 2.png)</p><p>![图片 3：立园建筑外观](images/图片 3.png)</p><p>![图片 4：桥头彩陶狮子与扇形装饰（贝壳纹灰塑）](images/图片 4.png)</p><p>![图片 5：泮立楼底层科林斯柱式与拱券门廊（本土化消解）](images/图片 5.png)</p><p>立园建于1926至1931年，主人谢维立是“最成功的那一拨”华侨。这座园林宅邸的实施条件极为优越，谢维立有充裕的经济资本，可利用全球的材料网络加上严格的工匠控制。这种封闭性、精英性、私人性的社会空间，使立园能够实施精密的“分离策略”。</p><p>立园主楼泮立楼（图2）垂直分层的文化逻辑清晰可辨，呈现典型的“三段式”结构：底层科林斯柱式与拱券门廊经过本土化消解，简化了柱头莨苕叶，结合广州的气候取消了柱身凹槽（图5），使西式元素成为服务性存在。建造者将标准层进行过渡性处理，窗套采用西式拱形但比例压缩，顶部绿色琉璃瓦的歇山顶完全统领视觉，排斥西式穹顶的显性表达。这种“去穹顶化”是有意识的文化选择。谢维立的海外成功无需通过穹顶证明，而是内化于材料品质之中。</p><p>桥头拍摄的彩陶狮子（图4）与扇形装饰显示，西式贝壳纹经灰塑工艺转化为本土装饰语汇，形成“似西非西”的杂交美学。</p><table tabindex="0"><thead><tr><th></th><th></th><th></th><th></th><th></th><th></th></tr></thead><tbody><tr><td></td><td>![图片 6：泮立居室内镂空木门与金漆横披](images/图片 6.png)</td><td></td><td>![图片 7：泮立居室内石膏灯盘装饰](images/图片 7.png)</td><td></td><td>![图片 8：泮立居室内葡萄纹装饰（葡萄藤与松鼠）](images/图片 8.png)</td></tr></tbody></table><p>![图片 9：泮文居楼梯间人物故事壁画与大理石楼梯](images/图片 9.png)</p><p>内部装饰的“隐性奢华”延续了分离逻辑。泮立居室内拍摄的镂空木门与金漆横披（图6），坚守中式内容与工艺。石膏灯盘与葡萄纹装饰（图7、图8）遵循“西式题材、中式工艺”的编码。葡萄藤象征丰收，松鼠寓意多子，形成跨文化的吉祥寓意嫁接。</p><p>泮文居楼梯间的人物故事壁画与大理石楼梯（图9）是“分离策略”的极致表达：壁画内容完全中式，但大理石的进口属性、楼梯的几何精度，体现技术现代性。</p><p>![图片 10：长廊&quot;飞天&quot;彩绘与山水梁画](images/图片 10.png)</p><p>![图片 11：门楼灰塑门楣与卷草纹装饰（莨苕叶简化）](images/图片 11.png)</p><p>长廊拍摄（图10)的“飞天””彩绘与山水梁画同样呈现这种“内容坚守、形式协商”敦煌壁画元素与岭南山水并置，女性形象的突破性出现与谢维立纳妾建园的史实互文。某门楼拍摄的灰塑门楣与卷草纹显示（图11），西式莨苕叶经灰塑工艺简化为平面图案，这种“不完美”的写实性恰恰形成独特的装饰风格——介于雕塑与绘画之间，介于写实与图案之间。</p><p>这种分离揭示了精英华侨的文化逻辑：身份认同锚定于中式内容，技术现代性体现于材料品质，形式传统性维持于视觉习惯。 与赤坎的“中西并置”不同，立园追求深层的和谐而非表层的对比。</p><h3 id="_2-2-赤坎古镇-商业街道的-表层竞争" tabindex="-1"><strong>2.2</strong> <strong>赤坎古镇：商业街道的“表层竞争”</strong> <a class="header-anchor" href="#_2-2-赤坎古镇-商业街道的-表层竞争" aria-label="Permalink to &quot;**2.2** **赤坎古镇：商业街道的“表层竞争”**&quot;">​</a></h3><p>与立园的封闭精英空间不同，赤坎古镇拥有三百余年历史，在1920至1930年期间形成六百余座骑楼的连续街景。数百个家族独立建造，每家通过柱式精致度、山花独特性、色彩鲜艳度争夺顾客注意力，形成“露天的建筑博物馆”。</p><p>![图片 12：赤坎古镇骑楼街景（柱式装饰竞争）](images/图片 12.png)</p><p>![图片 13：赤坎古镇骑楼街景（西式山花）](images/图片 13.png)</p><p>![图片 14：赤坎古镇骑楼街景（巴洛克曲线）](images/图片 14.png)</p><p>![图片 15：赤坎古镇骑楼街景（岭南直线与镬耳山墙）](images/图片 15.png)</p><p>水平界面的竞争性并置是赤坎的核心特征。西式山花与中式镬耳山墙在同一天际线上并置，巴洛克曲线与岭南直线形成视觉张力。这种“柱式即广告”的逻辑，使装饰符号成为商业竞争的工具——精细的科林斯柱头显示充裕资本，简化的几何柱头显示有限预算（图12-15）。</p><p>这种并置揭示了大众华侨的身份困境： 既无法完全西化，也无法彻底回归，只能在两者之间寻找临时的、协商的解决方案。与立园的“天衣无缝”相比，赤坎的并置是诚实的——它展示了协商的艰难，而非隐藏的和谐。</p><h3 id="三、-专业视角-装饰符号的技术史分析" tabindex="-1">**三、**<strong>专业视角：装饰符号的技术史分析</strong> <a class="header-anchor" href="#三、-专业视角-装饰符号的技术史分析" aria-label="Permalink to &quot;**三、****专业视角：装饰符号的技术史分析**&quot;">​</a></h3><h3 id="_3-1-水泥的-世界性-与-现代性" tabindex="-1"><strong>3.1</strong> <strong>水泥的“世界性””与“现代性”</strong> <a class="header-anchor" href="#_3-1-水泥的-世界性-与-现代性" aria-label="Permalink to &quot;**3.1** **水泥的“世界性””与“现代性”**&quot;">​</a></h3><p>![图片 16：灰塑装饰中西纹样交织（卷草纹、贝壳纹、涡卷纹）](images/图片 16.png)</p><p>![图片 17:祠堂书室&quot;林泉&quot;书法与花鸟壁画（丙申初夏李明书）](images/图片 17.png)</p><p>![图片 18:灰塑彩绘褪色与表面风化](images/图片 18.png)</p><p>![图片 19:灰塑表面风化粉化细节](images/图片 19.png)</p><p>水泥在开平建筑中的大规模使用，曾被视为建筑技术的革命性进步，但这种“现代性承诺””很快遭遇“现实挫败”。早期进口水泥质量不稳，部分碉楼出现碳化、开裂，暴露出技术移植过程中的适应性问题。让人意外的是，这种材料缺陷并未阻碍水泥的流行——恰恰因为水泥是进口商品，使用“红毛泥”本身就成为社会地位的象征，意味着拥有海外汇款渠道与世界贸易网络接入能力。同一材料在不同语境中被赋予不同功能，如立园以水泥黄墙营造奢华质感，赤坎则以水泥柱式塑造西洋立面，技术物质性与社会象征性在此交织。</p><h3 id="_3-2-灰塑题材的杂交与重构" tabindex="-1"><strong>3.2</strong> <strong>灰塑题材的杂交与重构</strong> <a class="header-anchor" href="#_3-2-灰塑题材的杂交与重构" aria-label="Permalink to &quot;**3.2** **灰塑题材的杂交与重构**&quot;">​</a></h3><p>灰塑是岭南传统技艺在开平的创新应用，也是中西装饰符号杂交的最典型载体。田野调查显示，这一工艺在立园天花、山花及赤坎古镇檐口均有密集分布，呈现出系统性的文化协商特征。</p><p>题材内容的杂交谱系在开平建筑的灰塑中清晰可辨（图16）：西式卷草纹、贝壳纹、涡卷纹与中式祥云纹、回纹在灰塑表面交织，开平建筑装饰呈现出独特的三重编码机制。西式题材构成形式资源库，中式工艺主导表现手法，以吉祥寓意实现文化转译。这一机制的具体运作可见于装饰纹样的生成过程。莨苕叶纹简化为单线轮廓，古典柱式的层叠立体感随之消解。涡卷纹趋于对称稳定，巴洛克式的动态戏剧性被有意弱化。贝壳纹则抽象为放射几何形态，从自然主义表现转向图案化处理。此类西式题材、中式工艺与吉祥寓意相互交织的复合编码模式，构成了开平建筑装饰的核心特征。</p><p>本次调研的田野记录提供了遗产保护的现状基准。调查显示彩绘褪色率较高，部分区域出现老旧脱落与表面风化粉化（图18、图19）。这些物理变化过程同时也是历史信息的层积，褪色反映了长期的光照历史，风化则铭刻着时间的深度。</p><p>仓东村传统民居拍摄的门楣灰塑与水果彩绘，显示本土工艺表现世俗题材的转变——从神圣教化到日常生活。祠堂书室拍摄的“林泉”书法与花鸟壁画，行草流畅的题字与旁署“丙申初夏李明书”（图17），展现文人雅趣与民间工艺的结合。</p><p>西式题材的本土化变异尤为显著。莨苕叶演变为卷草纹与石榴纹，“多子”的吉祥含义被植入；贝壳纹放大为扇形山花；葡萄藤蔓叙事化为松鼠葡萄。然而，当代“做旧”技术可以模拟风化，使真伪辨识困难，这种“技术的欺骗性”构成了保护伦理的挑战。</p><h3 id="_3-3-柱式装饰的本土化变异" tabindex="-1"><strong>3.3</strong> <strong>柱式装饰的本土化变异</strong> <a class="header-anchor" href="#_3-3-柱式装饰的本土化变异" aria-label="Permalink to &quot;**3.3** **柱式装饰的本土化变异**&quot;">​</a></h3><p>![图片 20:科林斯柱头本土化变异（莨苕叶平面化）](images/图片 20.png)</p><p>![图片 21:赤坎古镇圆形窗洞与宝瓶栏杆](images/图片 21.png)</p><p>![图片 22:宝瓶栏杆中式如意纹变形](images/图片 22.png)</p><p>![图片 23:立园彩色玻璃窗（黄绿透明三色符号系统）](images/图片 23.png)</p><p>西方古典柱式在开平经历了本土化变异。田野调查显示科林斯柱头的莨苕叶雕刻明显简化，叶片层叠结构趋向平面图案，柱身完全取消凹槽形成光滑圆柱（图20），柱间距加宽适应岭南炎热气候。这些变异构成“柱式”的本土变体——既保留垂直性与纪念性，又剥离古典的精致与秩序。</p><p>立园的柱式趋于融入园林氛围，赤坎的柱式趋于突出商业竞争，同一变体在不同策略中承担不同功能。然而，当代预制技术可以批量复制这些“变异”，使手工的痕迹、试错的过程、文化的过滤丧失殆尽。</p><h3 id="_3-4-其他中西融合元素的系统采集" tabindex="-1"><strong>3.4</strong> <strong>其他中西融合元素的系统采集</strong> <a class="header-anchor" href="#_3-4-其他中西融合元素的系统采集" aria-label="Permalink to &quot;**3.4** **其他中西融合元素的系统采集**&quot;">​</a></h3><p>赤坎古镇的建筑上部墙面，圆形窗洞连续排列，构成独特的视觉韵律。这一西方古典建筑元素在中国传统建筑中极为罕见，既可能象征天眼的宗教意涵，也可能纯粹服务于采光功能。宝瓶栏杆的分布同样广泛（图21、图22），西式宝瓶形式经本地水泥预制工艺转化，柱头偶有中式如意纹的变形处理。彩色玻璃窗则是开平建筑中最具现代性的装饰元素。立园客厅、卧室、楼梯间门窗的田野记录显示（图23），玻璃颜色黄、绿、透明三色形成符号系统。黄色过滤光线营造温暖氛围，绿色提供隐私保护，透明压花兼顾采光与纹理。这一西方宗教建筑元素的世俗化运用，采纳形式美感而剥离宗教内涵，进口材料创造戏剧化的光影效果。</p><h3 id="四、批判性思考-从-活态遗产-到-真实性危机" tabindex="-1"><strong>四、批判性思考：从“活态遗产”到“真实性危机”</strong> <a class="header-anchor" href="#四、批判性思考-从-活态遗产-到-真实性危机" aria-label="Permalink to &quot;**四、批判性思考：从“活态遗产”到“真实性危机”**&quot;">​</a></h3><h3 id="_4-1-仓东村的参照-新旧可识别-的伦理价值" tabindex="-1"><strong>4.1</strong> <strong>仓东村的参照：“新旧可识别”的伦理价值</strong> <a class="header-anchor" href="#_4-1-仓东村的参照-新旧可识别-的伦理价值" aria-label="Permalink to &quot;**4.1** **仓东村的参照：“新旧可识别”的伦理价值**&quot;">​</a></h3><p>仓东村作为原生态村落，提供了与立园、赤坎不同的保护模式。仓东村的“新旧可识别”原则使装饰符号成为时间层积的见证。这与立园的“修旧如旧”形成对比。立园追求新旧难以区分，目标是冻结某一理想的历史状态，而仓东村追求新旧可以辨识，目标是展示建筑的生长过程。然而，现代年轻人外流导致老龄化，传统生活方式难以为继，若未来盲目引入大规模旅游，可能破坏社区的活态性，使村民成为“表演的传统”的演员，重蹈赤坎的覆辙。</p><h3 id="_4-2-赤坎古镇的危机-真假并置-与真实性掏空" tabindex="-1"><strong>4.2</strong> <strong>赤坎古镇的危机：“真假并置”与真实性掏空</strong> <a class="header-anchor" href="#_4-2-赤坎古镇的危机-真假并置-与真实性掏空" aria-label="Permalink to &quot;**4.2** **赤坎古镇的危机：“真假并置”与真实性掏空**&quot;">​</a></h3><p>当代旅游开发彻底改变了赤坎的装饰符号逻辑。赤坎古镇采用“整体性改造”的模式，对整个镇区进行统一的规划、改造和开发。本次调研发现很多新建建筑采用“做旧”技术，如模拟建筑外立面遭受风化，用模具复制传统图案等手法，以达到使装饰符号在视觉上接近历史原物，但装饰符号在物质上完全属于当代。这种“真假并置”使观者难以辨识哪些是20世纪20年代的原物，哪些是现代的仿制，历史的真实性值得怀疑。</p><p>赤坎古镇作为旅游景区的统一规划对“历史风貌”过度追求，导致装饰元素的模板化复制，其建筑中柱式、山花、色彩等符号趋于同质化。这种“多样性中的统一”与历史原物“统一中的多样性”形成结构性反差。与此同时，商业开发还引入高饱和度动态光源，如霓虹灯、LED屏幕等，与历史建筑的沉稳色谱产生视觉冲突，这些都是商业化介入的典型症候。</p><h3 id="_4-3-诚实展示-一种保护伦理的提出" tabindex="-1"><strong>4.3</strong> <strong>“诚实展示”：一种保护伦理的提出</strong> <a class="header-anchor" href="#_4-3-诚实展示-一种保护伦理的提出" aria-label="Permalink to &quot;**4.3** **“诚实展示”：一种保护伦理的提出**&quot;">​</a></h3><p>遗产保护正面临真假并置的危机，诚实展示的伦理框架或许是一种转向。首先是识别与标识，开展建筑年代普查，建立真伪档案，解说牌明确告知访客所见的年代与性质。其次是流程透明，公开保护决策过程，让公众参与讨论，形成社会共识。最后是教育与提升，培养批判性观察能力，从拍照打卡转向深度理解。</p><h1 id="五、结论" tabindex="-1">五、结论 <a class="header-anchor" href="#五、结论" aria-label="Permalink to &quot;五、结论&quot;">​</a></h1><p>立园与赤坎的比较研究揭示了开平近代建筑中西文化协商的两种典型策略：“分离”与“并置”。前者体现于精英园林的深层和谐，后者呈现于商业街道的表层竞争。这两种策略表明，“中西融合”并非统一的美学范式，而是社会分层、身份政治与空间权力关系的物质化表达。从技术史视角审视，水泥的跨地域流通、灰塑的杂交工艺、柱式的本土变异、彩色玻璃的光学叙事，共同记录了近代技术移植过程中的文化过滤与创造性转化。</p><p>就遗产保护现状而言，开平建筑面临三重危机。立园的博物馆化倾向固化了历史状态，仓东村的人口流失威胁着活态传承，赤坎古镇的商业开发则导致真实性消解。有鉴于此，本研究提出诚实展示的保护伦理，主张超越风貌保护的视觉导向与旅游开发的经济逻辑，转向真实性管理的信息完整性与文化教育的公共价值建构，使开平近代建筑持续发挥活态档案的历史参照与伦理启示功能。</p>',67)])])}const m=t(o,[["render",n]]);export{l as __pageData,m as default};
